// Turbocharged HTML5 Canvas Fireworks — Hero Section
function FireworksCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let raf: number;
    let W = (canvas.width = canvas.parentElement?.clientWidth || window.innerWidth);
    let H = (canvas.height = canvas.parentElement?.clientHeight || 420);

    const onResize = () => {
      if (!canvas.parentElement) return;
      W = canvas.width = canvas.parentElement.clientWidth;
      H = canvas.height = canvas.parentElement.clientHeight;
    };
    window.addEventListener("resize", onResize);

    // Vivid neon palette
    const PALETTE = [
      "#FFD700", "#FF6A00", "#FF3CAC", "#00F0FF",
      "#A78BFA", "#39FF14", "#FFE066", "#F87171",
      "#34D399", "#60A5FA", "#F472B6", "#FBBF24",
    ];

    const rnd = (a: number, b: number) => a + Math.random() * (b - a);
    const pick = (arr: string[]) => arr[Math.floor(Math.random() * arr.length)];

    /* ── Spark particle ── */
    class Spark {
      x: number; y: number;
      vx: number; vy: number;
      alpha: number;
      color: string;
      size: number;
      decay: number;

      constructor(x: number, y: number, color: string, speed: number) {
        const angle = rnd(0, Math.PI * 2);
        this.x = x; this.y = y;
        this.vx = Math.cos(angle) * speed;
        this.vy = Math.sin(angle) * speed;
        this.alpha = rnd(0.85, 1);
        this.color = color;
        this.size = rnd(1.5, 3.2);
        this.decay = rnd(0.007, 0.018);
      }

      update() {
        this.vy += 0.06;         // gravity
        this.vx *= 0.98;         // air drag
        this.vy *= 0.98;
        this.x += this.vx;
        this.y += this.vy;
        this.alpha -= this.decay;
      }

      draw(c: CanvasRenderingContext2D) {
        c.save();
        c.globalAlpha = Math.max(0, this.alpha);
        c.shadowBlur = 16;
        c.shadowColor = this.color;
        c.fillStyle = this.color;
        c.beginPath();
        c.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        c.fill();
        c.restore();
      }
    }

    /* ── Glitter tail particle ── */
    class Glitter {
      x: number; y: number;
      vx: number; vy: number;
      alpha: number;
      color: string;

      constructor(x: number, y: number, color: string) {
        this.x = x; this.y = y;
        this.vx = rnd(-0.6, 0.6);
        this.vy = rnd(-0.6, 0.6);
        this.alpha = rnd(0.5, 0.9);
        this.color = color;
      }

      update() {
        this.vy += 0.04;
        this.x += this.vx;
        this.y += this.vy;
        this.alpha -= 0.025;
      }

      draw(c: CanvasRenderingContext2D) {
        c.save();
        c.globalAlpha = Math.max(0, this.alpha);
        c.shadowBlur = 8;
        c.shadowColor = this.color;
        c.fillStyle = this.color;
        c.beginPath();
        c.arc(this.x, this.y, 1.2, 0, Math.PI * 2);
        c.fill();
        c.restore();
      }
    }

    /* ── Rising rocket ── */
    class Rocket {
      x: number; y: number;
      vx: number; vy: number;
      targetY: number;
      color: string;
      exploded = false;
      trail: Glitter[] = [];

      constructor() {
        this.x = rnd(W * 0.1, W * 0.9);
        this.y = H + 10;
        this.targetY = rnd(H * 0.08, H * 0.55);
        const speed = rnd(10, 16);
        const drift = rnd(-1.5, 1.5);
        this.vx = drift;
        this.vy = -speed;
        this.color = pick(PALETTE);
      }

      update() {
        this.x += this.vx;
        this.y += this.vy;
        this.vy += 0.22;   // decelerate upward
        // leave glitter trail
        if (Math.random() < 0.7)
          this.trail.push(new Glitter(this.x, this.y, this.color));
        if (this.vy >= 0 || this.y <= this.targetY) {
          this.exploded = true;
        }
      }

      draw(c: CanvasRenderingContext2D) {
        // draw trail
        this.trail = this.trail.filter(g => { g.update(); g.draw(c); return g.alpha > 0; });
        // draw rocket head
        c.save();
        c.shadowBlur = 20;
        c.shadowColor = this.color;
        c.fillStyle = this.color;
        c.beginPath();
        c.arc(this.x, this.y, 3.5, 0, Math.PI * 2);
        c.fill();
        c.restore();
      }

      explode(sparks: Spark[], glitters: Glitter[]) {
        const count = Math.floor(rnd(100, 160)); // big burst
        const baseSpeed = rnd(4, 9);
        // random secondary colour for two-tone bursts
        const col2 = pick(PALETTE);
        for (let i = 0; i < count; i++) {
          const col = i % 3 === 0 ? col2 : this.color;
          sparks.push(new Spark(this.x, this.y, col, rnd(baseSpeed * 0.4, baseSpeed)));
        }
        // ring of glitter
        for (let i = 0; i < 40; i++) {
          glitters.push(new Glitter(this.x, this.y, this.color));
        }
        // flash burst drawn directly
        if (ctx) {
          ctx.save();
          ctx.globalAlpha = 0.35;
          const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, 60);
          g.addColorStop(0, this.color);
          g.addColorStop(1, "transparent");
          ctx.fillStyle = g;
          ctx.beginPath();
          ctx.arc(this.x, this.y, 60, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();
        }
      }
    }

    let rockets: Rocket[] = [];
    let sparks: Spark[] = [];
    let glitters: Glitter[] = [];

    // Stagger initial rockets so screen isn't empty on load
    for (let i = 0; i < 3; i++) {
      setTimeout(() => rockets.push(new Rocket()), i * 400);
    }

    const loop = () => {
      // Motion-blur fade (lower = longer trail)
      ctx.fillStyle = "rgba(6, 1, 15, 0.18)";
      ctx.fillRect(0, 0, W, H);

      // Spawn new rockets based on screen size to prevent lag
      const isMobile = W < 768;
      const maxRockets = isMobile ? 3 : 8;
      const spawnRate = isMobile ? 0.02 : 0.055;

      if (Math.random() < spawnRate && rockets.length < maxRockets)
        rockets.push(new Rocket());

      rockets = rockets.filter(r => {
        r.update();
        r.draw(ctx);
        if (r.exploded) {
          r.explode(sparks, glitters);
          return false;
        }
        return true;
      });

      sparks = sparks.filter(s => { s.update(); s.draw(ctx); return s.alpha > 0; });
      glitters = glitters.filter(g => { g.update(); g.draw(ctx); return g.alpha > 0; });

      raf = requestAnimationFrame(loop);
    };

    // Intersection Observer to pause animation when off-screen
    const observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) {
        if (!raf) loop();
      } else {
        if (raf) {
          cancelAnimationFrame(raf);
          raf = 0;
        }
      }
    });
    
    if (canvas) observer.observe(canvas);

    return () => {
      if (raf) cancelAnimationFrame(raf);
      window.removeEventListener("resize", onResize);
      if (canvas) observer.unobserve(canvas);
    };
  }, []);

  return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full pointer-events-none z-0" />;
}

function ProductsPageInner() {
  const { cartItems, addToCart, updateQuantity, setCartOpen } = useCart();
  const [categories, setCategories] = useState<Category[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [priceListUrl, setPriceListUrl] = useState("");
  const hasScrolledRef = useRef(false);

  const apiUrl = process.env.NEXT_PUBLIC_API_URL || "";

  useEffect(() => {
    async function loadData() {
      try {
        setLoading(true);
        const [catsRes, prodsRes, plRes] = await Promise.all([
          fetch(`${apiUrl}/api/categories`),
          fetch(`${apiUrl}/api/products`),
          fetch(`${apiUrl}/api/settings/price-list`).catch(() => null),
        ]);

        if (catsRes.ok && prodsRes.ok) {
          const catsData = await catsRes.json();
          const prodsData = await prodsRes.json();
          setCategories(catsData);
          setProducts(prodsData);
        }

        if (plRes && plRes.ok) {
          const plData = await plRes.json();
          setPriceListUrl(plData.url || "");
        }
      } catch (e) {
        console.error("Error loading products catalogue:", e);
      } finally {
        setLoading(false);
      }
    }
    loadData();
  }, [apiUrl]);

  // Auto-scroll to category when arriving from home page via ?scroll=category-sec-{id}
  const searchParams = useSearchParams();
  useEffect(() => {
    if (loading) return;                    // wait until products are in DOM
    if (hasScrolledRef.current) return;     // only scroll once per navigation
    const scrollTarget = searchParams.get("scroll");
    if (!scrollTarget) return;

    hasScrolledRef.current = true;

    // Retry up to 8 times (every 250ms = 2s total) until element is painted
    let attempts = 0;
    const tryScroll = () => {
      const el = document.getElementById(scrollTarget);
      if (el) {
        el.scrollIntoView({ behavior: "smooth", block: "start" });
      } else if (attempts < 8) {
        attempts++;
        setTimeout(tryScroll, 250);
      }
    };
    setTimeout(tryScroll, 300);
  }, [loading, searchParams]);

  const getCartQty = (productId: number) => {
    const item = cartItems.find((c) => c.id === productId);
    return item ? item.quantity : 0;
  };

  const handleScrollToCategory = (catId: number) => {
    const el = document.getElementById(`category-sec-${catId}`);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  // Filter products by search query
  const filteredProducts = React.useMemo(() => {
    if (!searchQuery) return products;
    return products.filter((p) =>
      p.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [products, searchQuery]);

  // Group filtered products by category
  const groupedProducts = React.useMemo(() => {
    return categories
      .map((cat) => {
        const catProds = filteredProducts.filter((p) => p.categoryId === cat.id);
        return {
          ...cat,
          products: catProds,
        };
      })
      .filter((group) => group.products.length > 0);
  }, [categories, filteredProducts]);

  return (
    <div className="min-h-screen bg-[#06010f] text-gray-100 flex flex-col font-['Outfit'] selection:bg-amber-400 selection:text-slate-950 overflow-x-hidden">
      {/* Navbar */}
      <Navbar priceListUrl={priceListUrl} />

      <main className="flex-grow pt-28 pb-20">
        {/* Hero Section with Canvas Fireworks Background */}
        <section className="relative h-[380px] md:h-[460px] flex items-center justify-center border-b border-white/5 bg-[#06010f] overflow-hidden">
          {/* Active Canvas Fireworks Background */}
          <FireworksCanvas />

          {/* Very light edge vignette — lets fireworks fully shine through the center */}
          <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,transparent_30%,rgba(6,1,15,0.75)_100%)] z-[1] pointer-events-none"></div>
          {/* Bottom fade into page background */}
          <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-[#06010f] to-transparent z-[1] pointer-events-none"></div>

          <div className="container mx-auto px-4 lg:px-8 relative z-10 text-center space-y-6 max-w-3xl">
            <span className="inline-flex items-center gap-1.5 px-4 py-1.5 rounded-full bg-gradient-to-r from-amber-400/10 to-yellow-500/10 border border-amber-400/30 text-amber-300 text-xs font-black uppercase tracking-[0.2em] shadow-lg shadow-amber-400/5 animate-pulse">
              ✨ Sivakasi Direct Wholesale Shop ✨
            </span>
            <h1 className="text-3xl md:text-5xl lg:text-6xl font-black uppercase tracking-tight text-white leading-tight">
              Premium Crackers <span className="bg-clip-text text-transparent bg-gradient-to-r from-yellow-300 via-amber-400 to-yellow-200 drop-shadow-[0_2px_15px_rgba(245,158,11,0.2)]">Price List</span>
            </h1>
            <p className="text-gray-300 text-sm md:text-sm max-w-2xl mx-auto font-medium leading-relaxed px-2">
              Purchase premium quality crackers directly from Sivakasi at factory wholesale rates. Simply select your items, adjust order quantities, and click checkout to instantly submit your booking via WhatsApp.
            </p>
            {products.length > 0 && Math.max(...products.map(p => p.discount || 0)) > 0 && (
              <div className="inline-block px-5 py-2.5 bg-gradient-to-r from-red-600/20 to-amber-600/20 border border-red-500/30 rounded-xl text-xs md:text-xs font-bold text-red-300 uppercase tracking-widest leading-normal">
                🎇 FESTIVE BUMPER OFFER: UP TO {Math.max(...products.map(p => p.discount || 0))}% DISCOUNT ON ALL ITEMS! 🎇
              </div>
            )}
          </div>
        </section>

        {/* Sticky Controls Panel (Glassmorphic Floating Bar) */}
        <section className="sticky top-16 md:top-20 z-30 py-4 px-4 bg-[#06010f]">
          <div className="w-full max-w-[95%] mx-auto bg-[#130925]/85 border border-white/[0.08] backdrop-blur-xl rounded-2xl md:rounded-full py-3.5 px-4 md:px-6 flex flex-col md:flex-row items-center justify-between gap-4 shadow-[0_20px_50px_rgba(0,0,0,0.6)] shadow-purple-950/20">
            {/* Search Input Container */}
            <div className="relative w-full md:w-80 group">
              <span className="absolute inset-y-0 left-0 pl-3.5 flex items-center text-amber-400 text-sm">
                ⚡
              </span>
              <input
                type="text"
                placeholder="Search crackers by name..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-9 pr-9 py-2.5 text-sm bg-black/40 border border-white/10 rounded-xl md:rounded-full text-white placeholder-gray-500 focus:outline-none focus:border-amber-400 focus:ring-2 focus:ring-amber-400/10 transition-all font-semibold shadow-inner group-hover:border-white/15"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery("")}
                  className="absolute inset-y-0 right-0 pr-3.5 flex items-center text-gray-400 hover:text-white text-sm cursor-pointer"
                >
                  ✕
                </button>
              )}
            </div>

            {/* Category Quick Scroll Navigation */}
            {categories.length > 0 && (
              <div className="w-full md:w-auto flex items-center gap-3 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
                <span className="text-[9px] font-black uppercase tracking-widest text-amber-400/80 bg-amber-400/5 border border-amber-400/10 px-2.5 py-1.5 rounded-lg flex-shrink-0">
                  📂 QUICK NAV:
                </span>
                <div className="flex items-center gap-2">
                  {categories.map((cat) => (
                    <button
                      key={cat.id}
                      onClick={() => handleScrollToCategory(cat.id)}
                      className="px-4 py-2 rounded-xl md:rounded-full bg-white/[0.03] border border-white/5 text-gray-300 text-xs font-black uppercase tracking-wider hover:bg-gradient-to-r hover:from-amber-400 hover:to-yellow-500 hover:text-slate-950 hover:border-transparent hover:scale-105 active:scale-95 hover:shadow-[0_0_15px_rgba(245,158,11,0.25)] transition-all cursor-pointer flex-shrink-0"
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </section>

        {/* Catalog Table Container */}
        <section className="w-full max-w-[95%] mx-auto px-4 lg:px-6 mt-6">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-28 gap-4">
              <div className="w-9 h-9 border-4 border-amber-400 border-t-transparent rounded-full animate-spin"></div>
              <span className="text-sm font-black uppercase tracking-widest text-amber-400/70 animate-pulse">
                Loading products database...
              </span>
            </div>
          ) : groupedProducts.length === 0 ? (
            <div className="text-center py-28 space-y-5 bg-white/[0.01] rounded-3xl border border-white/5 p-8 max-w-xl mx-auto">
              <span className="text-6xl animate-bounce inline-block">🎆</span>
              <p className="text-base font-black uppercase tracking-widest text-gray-400">
                No matching crackers found
              </p>
              <button
                onClick={() => setSearchQuery("")}
                className="px-6 py-3 rounded-full bg-gradient-to-r from-amber-400 to-yellow-500 text-slate-950 text-sm font-black uppercase tracking-widest hover:scale-105 active:scale-95 transition-all cursor-pointer shadow-lg shadow-amber-400/15"
              >
                Show All Products
              </button>
            </div>
          ) : (
            <div className="space-y-20">
              {groupedProducts.map((group) => (
                <div
                  key={group.id}
                  id={`category-sec-${group.id}`}
                  className="scroll-mt-40 space-y-6"
                >
                  {/* Category Section Header (Metallic Gold gradient lines) */}
                  <div className="flex items-center gap-4 pb-3 border-b-2 border-gradient-to-r border-amber-400/20">
                    <span className="text-2xl drop-shadow-[0_0_10px_rgba(245,158,11,0.5)]">🎇</span>
                    <h2 className="text-xl md:text-2xl font-black uppercase tracking-wider bg-clip-text text-transparent bg-gradient-to-r from-white via-amber-100 to-amber-300">
                      {group.name}
                    </h2>
                    <span className="text-[9px] font-black text-amber-400 bg-amber-400/10 border border-amber-400/20 px-3 py-1 rounded-full uppercase tracking-widest">
                      {group.products.length} Products
                    </span>
                  </div>

                  {/* Unified Responsive Card Grid View */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6">
                    {group.products.map((prod) => {
                      const qty = getCartQty(prod.id);
                      return (
                        <div
                          key={prod.id}
                          className="flex flex-col p-4 md:p-5 rounded-2xl border border-white/[0.05] bg-[#120a22]/55 backdrop-blur-xl shadow-2xl relative overflow-hidden group hover:border-amber-400/30 hover:shadow-[0_0_25px_rgba(245,158,11,0.15)] transition-all duration-300"
                        >
                          {/* Discount Badge */}
                          <div className="absolute top-3 right-3 z-10">
                            <span className="bg-gradient-to-r from-red-600 via-orange-600 to-amber-500 text-white font-black px-2.5 py-1 rounded-full text-[9px] tracking-widest shadow-md shadow-red-600/20 uppercase inline-flex items-center gap-1">
                              🔥 {prod.discount}% OFF
                            </span>
                          </div>

                          {/* Image Container */}
                          <div className="w-full h-40 md:h-48 rounded-xl border border-white/10 bg-white/5 flex items-center justify-center p-4 overflow-hidden mb-4 group-hover:border-amber-400/20 transition-colors">
                            <img
                              src={prod.image || "/assets/images/placeholder.png"}
                              alt={prod.name}
                              loading="lazy"
                              decoding="async"
                              className="w-full h-full object-contain group-hover:scale-110 transition-transform duration-500 drop-shadow-lg"
                            />
                          </div>

                          {/* Details */}
                          <div className="flex-1 flex flex-col">
                            <span className="text-[8px] font-black text-amber-400 bg-amber-400/5 border border-amber-400/10 px-2 py-0.5 rounded uppercase tracking-widest self-start mb-2">
                              {group.name}
                            </span>
                            <h4 className="font-bold text-white text-base md:text-base line-clamp-2 leading-snug mb-3 group-hover:text-amber-300 transition-colors">
                              {prod.name}
                            </h4>

                            <div className="mt-auto">
                              <div className="flex items-end gap-2.5 mb-4">
                                <span className="text-xl md:text-2xl font-black text-amber-400 drop-shadow-[0_0_10px_rgba(245,158,11,0.3)]">
                                  ₹{prod.price}
                                </span>
                                <span className="text-sm md:text-sm text-gray-500 line-through font-semibold pb-0.5">
                                  ₹{prod.originalPrice}
                                </span>
                              </div>

                              {/* Cart Actions */}
                              <div className="border-t border-white/5 pt-4">
                                {qty > 0 ? (
                                  <div className="flex items-center justify-between border border-amber-400/40 rounded-xl overflow-hidden bg-black/50 shadow-lg group-hover:border-amber-400/60 transition-all h-10 md:h-11">
                                    <button
                                      onClick={() => updateQuantity(prod.id, qty - 1)}
                                      className="flex-1 h-full text-amber-400 hover:bg-white/5 active:scale-95 transition-all cursor-pointer font-bold text-lg md:text-xl flex items-center justify-center"
                                    >
                                      −
                                    </button>
                                    <span className="px-4 h-full font-black text-white text-base md:text-base bg-white/5 flex items-center justify-center min-w-[3rem]">
                                      {qty}
                                    </span>
                                    <button
                                      onClick={() => updateQuantity(prod.id, qty + 1)}
                                      className="flex-1 h-full text-amber-400 hover:bg-white/5 active:scale-95 transition-all cursor-pointer font-bold text-lg md:text-xl flex items-center justify-center"
                                    >
                                      +
                                    </button>
                                  </div>
                                ) : (
                                  <button
                                    onClick={() =>
                                      addToCart({
                                        id: prod.id,
                                        name: prod.name,
                                        price: prod.price,
                                        originalPrice: prod.originalPrice,
                                        image: prod.image,
                                        category: group.name,
                                      })
                                    }
                                    className="w-full h-10 md:h-11 rounded-xl bg-gradient-to-r from-amber-400 via-yellow-300 to-amber-500 hover:from-yellow-300 hover:to-amber-500 text-slate-950 font-black uppercase text-xs md:text-xs tracking-widest hover:scale-[1.02] active:scale-95 transition-all cursor-pointer shadow-lg hover:shadow-amber-400/25 flex items-center justify-center gap-1.5 border border-amber-400/20"
                                  >
                                    <span>➕</span> ADD TO CART
                                  </button>
                                )}
                              </div>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>

      {/* Footer */}
      <Footer />

      {/* Contact floating widgets */}
      <ContactFloatingButtons />
    </div>
  );
}
export default function ProductsPage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-[#06010f]" />}>
      <ProductsPageInner />
    </Suspense>
  );
}
